s = "health"
# Unit 0 – Personal Health
add(g,s,0,0,[p("Name two good hygiene habits.","Daily health routines.","Brushing teeth twice daily, washing hands regularly, showering, changing clothes (any two).",E),p("Why is hand-washing important?","Prevents illness.","Removes germs that cause illness — especially before eating and after using the restroom.",E),p("How does good hygiene affect your social and emotional health?","Beyond the physical.","Feeling clean boosts confidence and self-esteem; it also shows respect for those around you.",M),p("List the steps for proper hand-washing.","WHO guidelines.","Wet hands, apply soap, scrub all surfaces for 20 seconds, rinse, dry with clean towel.",M),p("Design a daily hygiene checklist for a 6th grader.","Apply the habits.","Morning: brush teeth, shower/wash face, clean clothes. Evening: brush teeth, wash face, clean hands before meals.",H),p("How does poor hygiene contribute to the spread of infectious diseases? Give an example.","Transmission routes.","Not washing hands spreads fecal-oral diseases (like norovirus); coughing without covering spreads respiratory viruses.",H)])
add(g,s,0,1,[p("How many hours of sleep do 6th graders need per night?","Teen sleep needs.","8–10 hours per night is recommended for adolescents.",E),p("Name three nutrients your body needs.","Essential nutrients.","Proteins, carbohydrates, fats, vitamins, minerals, water (any three).",E),p("What is a balanced meal?","Plate composition.","A meal with proportionate amounts of vegetables, fruits, grains, proteins, and dairy/calcium sources.",M),p("How does lack of sleep affect school performance?","Sleep-learning link.","Poor sleep reduces concentration, memory consolidation, mood, and reaction time — all harm academic performance.",M),p("Compare the MyPlate food groups and the recommended proportions.","USDA guidelines.","Half the plate: fruits and vegetables. Quarter: grains (half whole grain). Quarter: protein. Side: dairy.",H),p("Explain why skipping breakfast is linked to lower performance at school.","Breaking the fast.","After overnight fasting, the brain needs glucose. Without breakfast, energy and focus drop — affecting memory and concentration.",H)])
add(g,s,0,2,[p("What is puberty?","Physical development period.","The process of physical changes through which a child's body develops into an adult's body.",E),p("Name one physical change that occurs during puberty.","Body changes.","Growth spurt, voice changes, body hair growth, skin changes, or reproductive development (any one).",E),p("Why do people develop at different rates during puberty?","Individual variation.","Genetics, nutrition, and hormones vary — starting age and pace differ from person to person (7–16 is normal range).",M),p("How can you take care of your mental health during puberty?","Emotional health.","Talk to trusted adults, maintain sleep and exercise routines, journal, spend time on hobbies, and avoid unhealthy comparison.",M),p("Describe three hormones active during puberty and their effects.","Hormones and growth.","Estrogen (female development), testosterone (male development, muscle growth), growth hormone (height increase).",H),p("How does nutrition particularly affect growth during puberty?","Growing bodies need more.","Puberty is the fastest growth period after infancy — calcium for bones, protein for muscle, iron for blood are especially critical.",H)])
add(g,s,0,3,[p("What is puberty education and why is it important?","Learning about development.","Education about physical and emotional changes during adolescence — helps young people understand normal development.",E),p("What is personal space?","Physical boundaries.","The physical distance people keep between themselves and others — respecting it is important for comfort and safety.",E),p("Why is it important for both boys and girls to learn about all aspects of puberty?","Mutual understanding.","Understanding everyone's experience promotes empathy, reduces stigma, and helps young people support their peers.",M),p("How can you respond respectfully if a peer is uncomfortable discussing puberty topics?","Respect boundaries.","Change the subject, avoid pressure, and respect their comfort level — everyone has different boundaries.",M),p("What resources are available to learn more about puberty in a safe way?","Trusted sources.","School counselors, health teachers, trusted parents/guardians, medical doctors, reputable websites (e.g., KidsHealth.org).",H),p("How does body positivity relate to puberty education?","Accepting your body.","Puberty education should include messages that all body types and development timelines are normal — reducing body shame and comparison.",H)])
add(g,s,0,4,[p("What is stress?","Body's response to challenges.","The body's reaction to demands or challenges — can be mental, emotional, or physical.",E),p("Give two healthy ways to manage stress.","Coping strategies.","Exercise, deep breathing, journaling, talking to someone, listening to music (any two).",E),p("What is the difference between positive stress (eustress) and negative stress (distress)?","Good vs. bad stress.","Eustress motivates (e.g., excitement before a game). Distress overwhelms and harms health.",M),p("Describe three physical signs that your body is under too much stress.","Physical symptoms.","Headaches, stomachaches, muscle tension, sleep problems, fatigue (any three).",M),p("Explain how exercise reduces stress at a biological level.","Endorphins.","Exercise releases endorphins — brain chemicals that reduce pain and create positive feelings, reducing cortisol (stress hormone).",H),p("Create a personal stress management plan with three strategies you would actually use.","Personalized plan.","Example: 1) Take a 15-min walk. 2) Write in a journal. 3) Talk to a friend. (Any three realistic personal strategies)",H)])
# Unit 1 – Physical Fitness
add(g,s,1,0,[p("Name the five components of physical fitness.","FITT components.","Cardiovascular endurance, muscular strength, muscular endurance, flexibility, body composition.",E),p("What is cardiovascular endurance?","Heart and lung fitness.","The ability of the heart and lungs to supply oxygen to muscles during sustained physical activity.",E),p("How does each component of fitness contribute to overall health?","Holistic fitness.","Cardio: heart health. Strength: bone density. Endurance: sustained activity. Flexibility: injury prevention. Body composition: metabolic health.",M),p("Which fitness component does swimming best develop?","Water activity.","Cardiovascular endurance — it's a sustained aerobic activity that works heart and lungs over time.",M),p("Create a weekly fitness plan that addresses at least three components.","Apply the components.","Mon: jog 20 min (cardio). Wed: push-ups/sit-ups (strength/endurance). Fri: yoga/stretching (flexibility).",H),p("How does knowing the components of fitness help you design a balanced exercise program?","Comprehensive training.","It ensures you don't neglect any aspect — a balanced program prevents injury and improves total body health.",H)])
add(g,s,1,1,[p("What is aerobic exercise?","Uses oxygen.","Physical activity that increases heart rate and breathing over a sustained period — uses oxygen for energy.",E),p("Give two examples of aerobic exercise.","Sustained activity.","Running, swimming, cycling, dancing, jump rope (any two).",E),p("How much aerobic exercise should a 6th grader get each day?","CDC guidelines.","At least 60 minutes of moderate-to-vigorous physical activity per day.",M),p("What are the long-term benefits of regular aerobic exercise?","Health benefits.","Stronger heart, lower blood pressure, weight management, better mood, reduced disease risk, improved sleep.",M),p("Explain what 'target heart rate zone' means and why it matters during aerobic exercise.","Optimal intensity.","The heart rate range (50–85% of max) where exercise is most effective for cardiovascular benefit — ensures adequate but not excessive intensity.",H),p("Compare moderate-intensity vs. vigorous-intensity aerobic activities. Give two examples of each.","Intensity levels.","Moderate: brisk walking, casual biking. Vigorous: running, fast swimming — vigorous provides greater cardio benefit in less time.",H)])
add(g,s,1,2,[p("What is stretching and why is it important?","Flexibility exercise.","Extending muscles to improve range of motion — prevents injury and improves posture.",E),p("What is the difference between strength and endurance?","How long vs. how heavy.","Strength: maximum force in one effort. Endurance: sustaining effort over multiple repetitions or time.",E),p("What is the best time to stretch — before or after exercise and why?","Stretch timing.","After exercise — muscles are warm and pliable, reducing risk of injury. Light dynamic movement before; static stretch after.",M),p("Describe two exercises that build core strength.","Core muscles.","Planks and sit-ups — both strengthen abdominal and back muscles that stabilize the spine.",M),p("Explain the FITT principle (Frequency, Intensity, Time, Type) as applied to flexibility training.","Apply FITT.","Frequency: 3+ days/week. Intensity: gentle stretch, no pain. Time: hold 15–30 sec per stretch. Type: yoga, static stretching.",H),p("How does improved flexibility reduce sports injuries?","Prevention mechanism.","Flexible muscles and tendons have more range of motion — less likely to tear when joints move unexpectedly during sport.",H)])
add(g,s,1,3,[p("What is the purpose of rules in team sports?","Structure and fairness.","Rules ensure fair play, safety, and a consistent structure for competition.",E),p("Name three team sports and one key rule for each.","Sport rules.","Soccer: no hands (except goalie). Basketball: can't travel. Baseball: 3 strikes and you're out.",E),p("What is sportsmanship?","Fair play attitude.","Playing by the rules, treating opponents with respect, and accepting wins and losses graciously.",M),p("How do team sports develop social skills?","Teamwork and communication.","Working with others requires communication, trust, leadership, conflict resolution, and shared goal-setting.",M),p("A teammate disagrees with your play decision during a game. How do you handle it?","Conflict on the field.","Acknowledge their view, discuss briefly, then commit to a decision — keep it positive and focused on the team goal.",H),p("Design a simple set of rules for a classroom sport activity promoting fair play.","Apply the concept.","1) Rotate positions fairly. 2) No arguing calls — designated referee decides. 3) No physical contact. 4) Everyone gets equal playing time.",H)])
add(g,s,1,4,[p("What is a fitness goal?","Specific health target.","A specific, measurable target for improving physical health.",E),p("What does SMART stand for in goal-setting?","Goal framework.","Specific, Measurable, Achievable, Relevant, Time-bound.",E),p("Write a SMART fitness goal for improving your running.","Apply SMART.","'I will run 1 mile in under 10 minutes within 6 weeks by practicing 3 times per week.'",M),p("Why is it important to track progress toward a fitness goal?","Monitoring progress.","Tracking shows what's working, keeps you motivated, and lets you adjust the plan if needed.",M),p("What should you do if you reach your fitness goal before your deadline?","Goal achieved.","Celebrate the achievement, set a new, more challenging SMART goal to continue improving.",H),p("Explain how short-term and long-term fitness goals work together.","Goal hierarchy.","Short-term goals (run 3x this week) build toward long-term goals (complete a 5K in 3 months) — each step supports the bigger vision.",H)])

