SUBJ_TEMPLATES = {
  "math": MATH_TEMPLATES, "science": SCI_TEMPLATES, "ela": ELA_TEMPLATES,
  "history": HIST_TEMPLATES, "cs": CS_TEMPLATES, "health": HEALTH_TEMPLATES,
}

def gen_problems(grade, subj, topic):
  templates = SUBJ_TEMPLATES.get(subj, MATH_TEMPLATES)
  return [{"q":q,"ex":ex,"a":a,"diff":d} for (q,ex,a,d) in [t(topic,grade) for t in templates]]

# ── Build full WORKSHEETS structure ───────────────────────────────────────────
WORKSHEETS = {}

# Grade 6 comes from hand-written DATA
WORKSHEETS[6] = {}
for subj, units_list in DATA[6].items():
  # units_list is dict: unit_idx -> topic_idx -> problems
  built_units = []
  for ui in sorted(units_list.keys()):
    topic_problems = units_list[ui]
    built_unit = []
    for ti in sorted(topic_problems.keys()):
      # find title from curriculum implied by position
      built_unit.append({"title": f"Topic {ti+1}", "problems": topic_problems[ti]})
    built_units.append(built_unit)
  WORKSHEETS[6][subj] = built_units

