# Grades 7-12: generate from curriculum + templates
for grade, subjects in CURRICULUM.items():
  WORKSHEETS[grade] = {}
  for subj, units in subjects.items():
    WORKSHEETS[grade][subj] = []
    for unit in units:
      unit_sheets = []
      for topic in unit["topics"]:
        unit_sheets.append({
          "title": topic,
          "problems": gen_problems(grade, subj, topic)
        })
      WORKSHEETS[grade][subj].append(unit_sheets)

